import java.lang.reflect.Method;
import java.lang.reflect.Type;

public class GsonToJsonTreeTest {

  private Gson gson;

  @BeforeEach
  public void setUp() {
    gson = new Gson();
  }

  @Test
  public void testToJsonTree_withNullSrcAndNullType() throws Exception {
    JsonElement result = gson.toJsonTree(null, (Type) null);
    assertNotNull(result);
    // JsonTreeWriter returns JsonNull.INSTANCE for null input
    assertEquals("null", result.toString());
  }

  @Test
  public void testToJsonTree_withPrimitiveType() throws Exception {
    Integer src = 123;
    JsonElement result = gson.toJsonTree(src, Integer.class);
    assertNotNull(result);
    assertEquals("123", result.toString());
  }

  @Test
  public void testToJsonTree_withStringType() throws Exception {
    String src = "testString";
    JsonElement result = gson.toJsonTree(src, String.class);
    assertNotNull(result);
    assertEquals("\"testString\"", result.toString());
  }

  @Test
  public void testToJsonTree_withObjectType() throws Exception {
    Object src = new Object();
    JsonElement result = gson.toJsonTree(src, Object.class);
    assertNotNull(result);
    // Object serializes to empty JSON object
    assertEquals("{}", result.toString());
  }

  @Test
  public void testToJsonTree_withArrayType() throws Exception {
    int[] src = new int[]{1, 2, 3};
    JsonElement result = gson.toJsonTree(src, int[].class);
    assertNotNull(result);
    assertEquals("[1,2,3]", result.toString());
  }

  @Test
  public void testToJsonTree_withGenericType() throws Exception {
    java.util.List<String> src = java.util.Arrays.asList("a", "b");
    Type type = new com.google.gson.reflect.TypeToken<java.util.List<String>>() {}.getType();
    JsonElement result = gson.toJsonTree(src, type);
    assertNotNull(result);
    assertEquals("[\"a\",\"b\"]", result.toString());
  }

  @Test
  public void testPrivateToJsonTreeUsingReflection() throws Exception {
    Method toJsonTreeMethod = Gson.class.getDeclaredMethod("toJsonTree", Object.class, Type.class);
    toJsonTreeMethod.setAccessible(true);

    String src = "reflectionTest";
    Type type = String.class;

    JsonElement result = (JsonElement) toJsonTreeMethod.invoke(gson, src, type);
    assertNotNull(result);
    assertEquals("\"reflectionTest\"", result.toString());
  }
}
